export const IconR = ({
  isLink = false,
  style = {},
}: {
  isLink?: boolean;
  style?: React.CSSProperties;
}) => {
  style.width = isLink ? "1.4rem" : "1rem";
  return (
    <img
      loading="lazy"
      referrerPolicy="no-referrer"
      crossOrigin="anonymous"
      src="img/r.ico"
      style={style}
      alt="r Property"
    />
  );
};

