import "./App.css";
import Summary from "../Summary/Summary";
import Pagination from "../Pagination/Pagination";
import ItemCard from "../ItemCard/ItemCard";
import { Spinner } from "../Simple/Spinner";

import { useState, useEffect } from "../../cdn";
import type { Item } from "../../types";

export const App = () => {
  // @ts-ignore: React prod lacks typesctipt info for useState
  const [data, setData] = useState<any>({ __loading: true });
  // @ts-ignore: React prod lacks typesctipt info
  const [itemsSelectable, setItemsSelectable] = useState<Item[]>([]);
  // @ts-ignore: React prod lacks typesctipt info
  const [itemsDisplayed, setItemsDisplayed] = useState<Item[]>([]);
  const [activePage1, setActivePage1] = useState(1);

  const PAGE_LENGTH = 10;
  const fetchData = async () => {
    try {
      //e.g. http://localhost:3000/?data=rightmove_chesterfiled
      let fileNoExt = new URLSearchParams(window.location.search).get("data");

      const next_on = localStorage.getItem(`${fileNoExt}__next_on`);
      const last_attempt = localStorage.getItem(`${fileNoExt}__last_attempt`);
      const now = new Date().valueOf();
      let cacheOpt;
      const info = document.querySelector("#x-spinner-info") as HTMLElement;
      if (last_attempt && now - new Date(last_attempt).valueOf() < 3000) {
        info.innerText = "FORCE RELOAD due to 2 attempts within 3s";
        cacheOpt = "reload";
      } else if (next_on) {
        if (new Date(next_on).valueOf() > now) {
          info.innerText = "Keep CACHED data";
          cacheOpt = "force-cache";
        } else {
          info.innerText = "RELOADING as cache data expired";
          cacheOpt = "reload";
        }
      } else {
        info.innerText = "LOAD first time";
        cacheOpt = "reload";
      }

      const url = `https://raw.githubusercontent.com/solfegedev/solfegedev.github.io/main/data/${fileNoExt}.json`;
      console.log(`Fetch data from server: ${url}`);
      const response = await fetch(url, { cache: cacheOpt } as RequestInit);
      if (!response.ok) {
        const msg =
          response.status === 404
            ? `This link seems wrong, check you have the correct one`
            : `Failed to get data for: ${fileNoExt}`;
        throw new Error(msg);
      }
      const data = await response.json();
      localStorage.setItem(`${fileNoExt}__next_on`, new Date(data.next_on).toISOString());
      localStorage.setItem(`${fileNoExt}__last_attempt`, new Date().toISOString());

      //DEBUG: data.items = data.items.slice(42, 44);
      // data.items[0].is_new = true;

      setData(data);
    } catch (error) {
      setData({ __error: `${error}` });
    }
  };
  useEffect(() => {
    fetchData();
  }, []);

  if (data.favicon) {
    const link = document.querySelector("link[rel='icon']") as HTMLLinkElement;
    link.href = `img/${data.favicon}`;
  }

  document.title = process.env.NODE_ENV === "development" ? "DEVELOPMENT" : data.region;

  if (data.__loading) {
    return (
      <main>
        <Spinner style={{ fontSize: "5rem", marginTop: "10rem" }} />
        <p id="x-spinner-info" style={{ fontStyle: "italic", marginTop: "1rem" }} />
      </main>
    );
  } else if (data.__error) {
    return <main style={{ color: "red" }}>{data.__error}</main>;
  } else {
    const propStart = (activePage1 - 1) * PAGE_LENGTH + 1;
    const propLast = itemsSelectable.length;
    const propEnd = Math.min(propLast, propStart + PAGE_LENGTH - 1);
    const pgElem = (
      <Pagination
        items={itemsSelectable}
        setItemsDisplayed={setItemsDisplayed}
        activePage1={activePage1}
        setActivePage1={setActivePage1}
        PAGE_LENGTH={PAGE_LENGTH}
      />
    );
    return (
      <main>
        <Summary
          data={data}
          setItemsSelectable={setItemsSelectable}
          setActivePage1={setActivePage1}
        />
        <div id="x-scroll-anchor">
          {pgElem}
          {propLast === 0 ? (
            <p>
              <strong>No matching results</strong>
            </p>
          ) : (
            <p>
              Page <strong>{activePage1}</strong>: properties <strong>{propStart}</strong> -
              <strong>{propEnd}</strong> out of <strong>{propLast}</strong>
            </p>
          )}
          {itemsDisplayed &&
            itemsDisplayed.map((item: Item, index: number) => {
              return <ItemCard key={index} item={item} />;
            })}
        </div>
        {pgElem}
      </main>
    );
  }
};

export default App;
