export const Elem = ({
  icon,
  text,
  url = "",
}: {
  icon: React.ReactNode;
  text: string;
  url?: string;
}) => {
  const txtElem = url ? (
    <a rel="noreferrer" target="_blank" href={url}>
      {text}
    </a>
  ) : (
    text
  );
  return (
    <span className="x-nowrap">
      {icon} {txtElem}
    </span>
  );
};
